  enum Op
  {
    kINVALID,
    kPos,
    kNeg,
    kNot
  };

  Op op{ kINVALID };
  Expr* sub{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct BinaryExpr : Expr
{
  enum Op
  {
    kINVALID,
    kMul,
    kDiv,
    kMod,
    kAdd,
    kSub,
    kGt,
    kLt,
    kGe,
    kLe,
    kEq,
    kNe,
    kAnd,
    kOr,
    kAssign,
    kComma,
    kIndex,
  };

  Op op{ kINVALID };
  Expr *lft{ nullptr }, *rht{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct CallExpr : Expr
{
  Expr* head{ nullptr };
  std::vector<Expr*> args;

private:
  void __mark__(Mark mark) override;
};

struct InitListExpr : Expr
{
  std::vector<Expr*> list;

private:
  void __mark__(Mark mark) override;
};

struct ImplicitInitExpr : Expr
{};

struct ImplicitCastExpr : Expr
{
  enum
  {
    kINVALID,
    kLValueToRValue,
    kIntegralCast,
    kArrayToPointerDecay,
    kFunctionToPointerDecay,
    kNoOp,
  } kind{ kINVALID };
  Expr* sub{ nullptr };

private:
  void __mark__(Mark mark) override;
};

//==============================================================================
// 语句
//==============================================================================

struct FunctionDecl;

struct Stmt : Obj
{};

struct NullStmt : Stmt
{
protected:
  void __mark__(Mark mark) override;
};

struct DeclStmt : Stmt
{
  std::vector<Decl*> decls;

private:
  void __mark__(Mark mark) override;
};

struct ExprStmt : Stmt
{
  Expr* expr{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct CompoundStmt : Stmt
{
  std::vector<Stmt*> subs;

private:
  void __mark__(Mark mark) override;
};

struct IfStmt : Stmt
{
  Expr* cond{ nullptr };
  Stmt *then{ nullptr }, *else_{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct WhileStmt : Stmt
{
  Expr* cond{ nullptr };
  Stmt* body{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct DoStmt : Stmt
{
  Stmt* body{ nullptr };
  Expr* cond{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct BreakStmt : Stmt
{
  Stmt* loop{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct ContinueStmt : Stmt
{
  Stmt* loop{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct ReturnStmt : Stmt
{
  FunctionDecl* func{ nullptr };
  Expr* expr{ nullptr };

private:
  void __mark__(Mark mark) override;
};

//==============================================================================
// 声明
//==============================================================================

struct Decl : Obj
{
  const Type* type;
  std::string name;

protected:
  void __mark__(Mark mark) override;
};

struct VarDecl : Decl
{
  Expr* init{ nullptr };

private:
  void __mark__(Mark mark) override;
};

struct FunctionDecl : Decl
{
  std::vector<Decl*> params;
  CompoundStmt* body{ nullptr };

private:
  void __mark__(Mark mark) override;
};

//==============================================================================
// 顶层
//==============================================================================

struct TranslationUnit : Obj
{
  std::vector<Decl*> decls;

private:
  void __mark__(Mark mark) override;
};

} // namespace asg
